class InputSanitizationFilter(logging.Filter):
    """Filter that sanitizes log messages to prevent log injection attacks."""

    def filter(self, record):
        if isinstance(record.msg, str):
            record.msg = self._sanitize(record.msg)
        if record.args:
            if isinstance(record.args, dict):
                record.args = {k: self._sanitize(str(v)) if isinstance(v, str) else v
                               for k, v in record.args.items()}
            elif isinstance(record.args, tuple):
                record.args = tuple(
                    self._sanitize(str(a)) if isinstance(a, str) else a
                    for a in record.args
                )
        return True

    @staticmethod
    def _sanitize(message):
        # Remove or escape newlines and carriage returns to prevent log injection
        message = message.replace('\r\n', '\\r\\n')
        message = message.replace('\n', '\\n')
        message = message.replace('\r', '\\r')
        # Remove null bytes
