def _ensure_secure_log_directory():
    """Create the log directory with secure permissions if it doesn't exist."""
    if not os.path.exists(LOG_DIR):
        try:
            os.makedirs(LOG_DIR, mode=SECURE_DIR_PERMISSIONS, exist_ok=True)
        except OSError as e:
            sys.stderr.write(f"CRITICAL: Cannot create log directory {LOG_DIR}: {e}\n")
            raise

    # Verify and enforce directory permissions
    try:
        current_stat = os.stat(LOG_DIR)
        current_mode = stat.S_IMODE(current_stat.st_mode)

        # Check that the directory is not world-readable or world-writable
        if current_mode & (stat.S_IROTH | stat.S_IWOTH | stat.S_IXOTH):
            sys.stderr.write(
                f"WARNING: Log directory {LOG_DIR} has world-accessible permissions. "
                f"Tightening to {oct(SECURE_DIR_PERMISSIONS)}.\n"
            )
            os.chmod(LOG_DIR, SECURE_DIR_PERMISSIONS)

        # Check that the directory is not group-writable
        if current_mode & stat.S_IWGRP:
            sys.stderr.write(
                f"WARNING: Log directory {LOG_DIR} is group-writable. "
                f"Tightening permissions.\n"
            )
            os.chmod(LOG_DIR, SECURE_DIR_PERMISSIONS)

    except OSError as e:
        sys.stderr.write(f"WARNING: Cannot verify permissions on {LOG_DIR}: {e}\n")

    # Verify the path is not a symlink (prevent symlink attacks)
    if os.path.islink(LOG_DIR):
        raise SecurityError(
            f"Log directory {LOG_DIR} is a symbolic link. "
            f"This is not allowed for security reasons."
        )


