def log_security_event(event_type, description, user=None, ip_address=None,
                       success=True, app_name="application"):
    """
    Log a security-relevant event to the audit log.

    Args:
        event_type: Type of security event (e.g., 'AUTH', 'ACCESS', 'ADMIN').
        description: Human-readable description of the event.
        user: Username or user ID (will not log passwords or tokens).
        ip_address: Source IP address if available.
        success: Whether the action was successful.
        app_name: Application name for logger lookup.
    """
    audit_logger = get_audit_logger(app_name)

    # Sanitize inputs - only allow expected characters
    safe_event_type = re.sub(r'[^A-Z_]', '', str(event_type)[:50])
    safe_description = str(description)[:500]
    status = "SUCCESS" if success else "FAILURE"

    parts = [f"SECURITY_EVENT={safe_event_type}", f"status={status}"]

    if user is not None:
        # Sanitize user identifier
        safe_user = re.sub(r'[^\w@.\-]', '', str(user)[:100])
        parts.append(f"user={safe_user}")

    if ip_address is not None:
        # Basic IP address validation
        safe_ip = re.sub(r'[^0-9a-fA-F.:]', '', str(ip_address)[:45])
        parts.append(f"ip={safe_ip}")

    parts.append(f"detail={safe_description}")

    audit_logger.info(" | ".join(parts))


